import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";const o=JSON.parse(`{"title":"Обновление Fabric на Linux","description":"Пошаговое руководство по обновлению Fabric в Linux.","frontmatter":{"title":"Обновление Fabric на Linux","description":"Пошаговое руководство по обновлению Fabric в Linux.","authors":["IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"ru_ru/players/updating-fabric/linux.md","filePath":"translated/ru_ru/players/updating-fabric/linux.md","lastUpdated":1770561656000}`);var s={name:`ru_ru/players/updating-fabric/linux.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Обновление Fabric на Linux <a class="header-anchor" href="#h1" aria-label="Permalink to “Обновление Fabric на Linux”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Загрузка установщика Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Загрузка установщика Fabric”">​</a></h2><p>Загрузите версию Fabric Installer в формате <code>.jar</code> с <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">веб-сайта Fabric</a>, нажав на кнопку <code>Download installer (Universal/.JAR)</code>.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Запуск установщика Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Запуск установщика Fabric”">​</a></h2><p>Перед запуском установщика сначала закройте Minecraft и Minecraft Launcher.</p><p>Откройте терминал и запустите установщик с помощью Java:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -jar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer.jar</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>После запуска установщика вы должны увидеть экран, похожий на этот:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Установщик Fabric с подсвеченным «Установить»" loading="lazy"></p><p>Убедитесь в том что новая версия игры и версия загрузчика корректны, затем нажмите &#39;Установить&#39; чтобы обновить Fabric.</p><div class="warning custom-block"><p class="custom-block-title">ВАЖНО</p><p>Обязательно снимите флажок «Создать профиль» при запуске программы установки!</p></div><h2 id="3-update-launcher-profile" tabindex="-1">3. Обновление профиля в Minecraft Launcher <a class="header-anchor" href="#3-update-launcher-profile" aria-label="Permalink to “3. Обновление профиля в Minecraft Launcher”">​</a></h2><p>После завершения установки откройте Minecraft Launcher. Затем перейдите на вкладку «Установки». Найдите свой профиль Fabric и откройте экран его редактирования:</p><p><img src="/assets/players/updating-fabric.png" alt="Обновление версии Fabric Loader в Minecraft Launcher" loading="lazy"></p><p>Замените версию на новую версию Fabric Loader, которую вы только что установили, и нажмите «Сохранить».</p><h2 id="4-you-re-done" tabindex="-1">4. Готово! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. Готово!”">​</a></h2><p>Выполнив эти шаги, вы можете вернуться на вкладку <code>Играть</code>, выбрать профиль Fabric из раскрывающегося списка в левом нижнем углу и нажмите играть!</p><p>Если у вас возникнут проблемы при выполнении инструкций этого руководства, вы можете обратиться за помощью в <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> в канале <code>#player-support</code>.</p>`,18)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};